#include <stdio.h>
#include <stdlib.h>

// Structure representing a node in the binary tree
typedef struct Node {
    int data;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new node
Node* createNode(int data) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->data = data;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to get the top view of the binary tree
void topView(Node* root) {
    if (root == NULL) return;

    // Create a queue for BFS and enqueue the root node
    Node** queue = (Node**) malloc(sizeof(Node*) * 100000);
    int front = 0, rear = 0;
    queue[rear++] = root;

    // Create a map to store the top view nodes
    int* topViewNodes = (int*) malloc(sizeof(int) * 100000);
    int topViewSize = 0;

    // Perform BFS
    while (front < rear) {
        Node* currentNode = queue[front++];

        // If the current node is not NULL, enqueue its children
        if (currentNode != NULL) {
            if (currentNode->left != NULL) queue[rear++] = currentNode->left;
            if (currentNode->right != NULL) queue[rear++] = currentNode->right;
        }

        // If the current node is at the top view, add it to the top view nodes array
        if (currentNode != NULL && (currentNode->left == NULL || currentNode->right == NULL)) {
            topViewNodes[topViewSize++] = currentNode->data;
        }
    }

    // Print the top view nodes
    for (int i = 0; i < topViewSize; i++) {
        printf("%d ", topViewNodes[i]);
    }
    printf("\n");
}

int main() {
    // Create the binary tree
    Node* root = createNode(1);
    root->left = createNode(2);
    root->right = createNode(3);
    root->left->left = createNode(4);
    root->left->right = createNode(5);
    root->right->left = createNode(6);
    root->right->right = createNode(7);

    // Get the top view of the binary tree
    topView(root);

    return 0;
}

