import java.util.HashMap;
import java.util.Map;
import java.util.Queue;
import java.util.LinkedList;

// Class representing a node in the binary tree
class Node {
    int data;
    Node left;
    Node right;

    public Node(int data) {
        this.data = data;
        this.left = null;
        this.right = null;
    }
}

public class Main {
    // Function to get the top view of the binary tree
    public static void topView(Node root) {
        if (root == null) return;

        // Create a queue for BFS and enqueue the root node
        Queue<Node> q = new LinkedList<>();
        q.add(root);

        // Create a map to store the top view nodes
        Map<Integer, Integer> topViewNodes = new HashMap<>();

        // Perform BFS
        while (!q.isEmpty()) {
            Node currentNode = q.poll();

            // If the current node is not NULL, enqueue its children
            if (currentNode != null) {
                if (currentNode.left != null) q.add(currentNode.left);
                if (currentNode.right != null) q.add(currentNode.right);
            }

            // If the current node is at the top view, add it to the top view nodes map
            if (currentNode != null && (currentNode.left == null || currentNode.right == null)) {
                topViewNodes.put(currentNode.data, currentNode.data);
            }
        }

        // Print the top view nodes
        for (Map.Entry<Integer, Integer> entry : topViewNodes.entrySet()) {
            System.out.print(entry.getValue() + " ");
        }
        System.out.println();
    }

    public static void main(String[] args) {
        // Create the binary tree
        Node root = new Node(1);
        root.left = new Node(2);
        root.right = new Node(3);
        root.left.left = new Node(4);
        root.left.right = new Node(5);
        root.right.left = new Node(6);
        root.right.right = new Node(7);

        // Get the top view of the binary tree
        topView(root);
    }
}

